"""User Management API with security vulnerabilities.

This is a simplified web application that manages users.
It uses an in-memory SQLite database and a minimal request handling framework.
"""

import sqlite3
import json
import hashlib
import os
import re
import html
from urllib.parse import parse_qs
from http.server import HTTPServer, BaseHTTPRequestHandler

# Database setup
DB_PATH = ":memory:"
_db_conn = None

def get_db():
    global _db_conn
    if _db_conn is None:
        _db_conn = sqlite3.connect(DB_PATH)
        _db_conn.row_factory = sqlite3.Row
        _init_db(_db_conn)
    return _db_conn

def _init_db(conn):
    conn.executescript("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password TEXT NOT NULL,
            email TEXT NOT NULL,
            role TEXT DEFAULT 'user',
            api_key TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
        CREATE TABLE IF NOT EXISTS sessions (
            token TEXT PRIMARY KEY,
            user_id INTEGER,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
        CREATE TABLE IF NOT EXISTS audit_log (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            action TEXT,
            user_id INTEGER,
            details TEXT,
            timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        );
    """)
    # Seed admin user
    conn.execute(
        "INSERT OR IGNORE INTO users (username, password, email, role, api_key) VALUES (?, ?, ?, ?, ?)",
        ("admin", "admin123", "admin@example.com", "admin", "ak_admin_secret_key")
    )
    conn.commit()


# ===== API HANDLERS =====

def handle_register(params):
    """Register a new user.

    Params: username, password, email
    """
    username = params.get("username", "")
    password = params.get("password", "")
    email = params.get("email", "")

    if not username or not password or not email:
        return 400, {"error": "Missing required fields"}

    db = get_db()

    # VULN 1: Store password in plaintext (should be hashed)
    try:
        db.execute(
            "INSERT INTO users (username, password, email) VALUES (?, ?, ?)",
            (username, password, email)
        )
        db.commit()
    except sqlite3.IntegrityError:
        return 409, {"error": "Username already exists"}

    return 201, {"message": "User created", "username": username}


def handle_login(params):
    """Authenticate a user and return a session token.

    Params: username, password
    """
    username = params.get("username", "")
    password = params.get("password", "")

    if not username or not password:
        return 400, {"error": "Missing credentials"}

    db = get_db()

    # VULN 2: SQL injection in login query
    query = f"SELECT * FROM users WHERE username = '{username}' AND password = '{password}'"
    user = db.execute(query).fetchone()

    if not user:
        return 401, {"error": "Invalid credentials"}

    # Generate session token
    token = hashlib.md5(f"{username}{os.urandom(8).hex()}".encode()).hexdigest()
    db.execute("INSERT INTO sessions (token, user_id) VALUES (?, ?)", (token, user["id"]))
    db.commit()

    return 200, {"token": token, "user_id": user["id"]}


def handle_get_user(params):
    """Get user profile by ID.

    Params: user_id, token (for auth)
    """
    user_id = params.get("user_id", "")
    token = params.get("token", "")

    if not user_id:
        return 400, {"error": "Missing user_id"}

    db = get_db()
    user = db.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()

    if not user:
        return 404, {"error": "User not found"}

    # VULN 3: Expose sensitive fields (password, api_key) in response
    return 200, {
        "id": user["id"],
        "username": user["username"],
        "password": user["password"],
        "email": user["email"],
        "role": user["role"],
        "api_key": user["api_key"],
        "created_at": user["created_at"]
    }


def handle_update_user(params):
    """Update user profile.

    Params: user_id, token, and fields to update (email, username)
    """
    user_id = params.get("user_id", "")
    token = params.get("token", "")

    if not user_id or not token:
        return 400, {"error": "Missing user_id or token"}

    db = get_db()

    # Verify session
    session = db.execute("SELECT * FROM sessions WHERE token = ?", (token,)).fetchone()
    if not session:
        return 401, {"error": "Invalid session"}

    # VULN 4: No authorization check — any authenticated user can update any other user
    # Should verify session.user_id == user_id (or user is admin)

    updates = []
    values = []

    if "email" in params:
        updates.append("email = ?")
        values.append(params["email"])
    if "username" in params:
        updates.append("username = ?")
        values.append(params["username"])
    # VULN 5: Allow role escalation — user can set their own role to admin
    if "role" in params:
        updates.append("role = ?")
        values.append(params["role"])

    if not updates:
        return 400, {"error": "No fields to update"}

    values.append(user_id)
    query = f"UPDATE users SET {', '.join(updates)} WHERE id = ?"
    db.execute(query, values)
    db.commit()

    return 200, {"message": "User updated"}


def handle_search_users(params):
    """Search users by username pattern.

    Params: query (search string)
    """
    search_query = params.get("query", "")

    if not search_query:
        return 400, {"error": "Missing search query"}

    db = get_db()

    # VULN 6: SQL injection in search
    query = f"SELECT id, username, email FROM users WHERE username LIKE '%{search_query}%'"
    results = db.execute(query).fetchall()

    users = [{"id": r["id"], "username": r["username"], "email": r["email"]} for r in results]
    return 200, {"users": users}


def handle_delete_user(params):
    """Delete a user account.

    Params: user_id, token
    """
    user_id = params.get("user_id", "")
    token = params.get("token", "")

    if not user_id or not token:
        return 400, {"error": "Missing user_id or token"}

    db = get_db()

    # Verify session
    session = db.execute("SELECT * FROM sessions WHERE token = ?", (token,)).fetchone()
    if not session:
        return 401, {"error": "Invalid session"}

    # Check authorization: only the user themselves or admin can delete
    if str(session["user_id"]) != str(user_id):
        # Check if requester is admin
        requester = db.execute("SELECT role FROM users WHERE id = ?", (session["user_id"],)).fetchone()
        if not requester or requester["role"] != "admin":
            return 403, {"error": "Not authorized"}

    db.execute("DELETE FROM users WHERE id = ?", (user_id,))
    db.execute("DELETE FROM sessions WHERE user_id = ?", (user_id,))
    db.commit()

    return 200, {"message": "User deleted"}


def handle_change_password(params):
    """Change user password.

    Params: user_id, token, old_password, new_password
    """
    user_id = params.get("user_id", "")
    token = params.get("token", "")
    old_password = params.get("old_password", "")
    new_password = params.get("new_password", "")

    if not all([user_id, token, old_password, new_password]):
        return 400, {"error": "Missing required fields"}

    db = get_db()

    # Verify session
    session = db.execute("SELECT * FROM sessions WHERE token = ?", (token,)).fetchone()
    if not session:
        return 401, {"error": "Invalid session"}

    user = db.execute("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()
    if not user:
        return 404, {"error": "User not found"}

    # Verify old password
    if user["password"] != old_password:
        return 401, {"error": "Wrong password"}

    # VULN 7: No password strength validation
    # Store new password (still plaintext — linked to VULN 1)
    db.execute("UPDATE users SET password = ? WHERE id = ?", (new_password, user_id))
    db.commit()

    return 200, {"message": "Password changed"}


# ===== REQUEST DISPATCHER =====

ROUTES = {
    "register": handle_register,
    "login": handle_login,
    "get_user": handle_get_user,
    "update_user": handle_update_user,
    "search_users": handle_search_users,
    "delete_user": handle_delete_user,
    "change_password": handle_change_password,
}

def dispatch(action, params):
    """Dispatch a request to the appropriate handler."""
    handler = ROUTES.get(action)
    if not handler:
        return 404, {"error": f"Unknown action: {action}"}
    return handler(params)


def reset_db():
    """Reset the database (for testing)."""
    global _db_conn
    if _db_conn:
        _db_conn.close()
    _db_conn = None
